class Solution:
    def handleQuery(self, nums1, nums2, queries):
        a = list(nums1)
        b = list(nums2)
        res = []
        for q in queries:
            t = q[0]
            if t == 1:
                l, r = q[1], q[2]
                for i in range(l, r + 1):
                    a[i] ^= 1
            elif t == 2:
                p = q[1]
                for i in range(len(b)):
                    b[i] += a[i] * p
            else:
                res.append(sum(b))
        return res

