class Solution:
    def handleQuery(self, nums1, nums2, queries):
        n = len(nums1)
        size = 1
        while size < n:
            size *= 2
        ones = [0] * (2 * size)
        length = [0] * (2 * size)
        lazy = [False] * (2 * size)
        for i in range(size):
            length[size + i] = 1
        for i in range(size - 1, 0, -1):
            length[i] = length[2 * i] + length[2 * i + 1]
        for i in range(n):
            ones[size + i] = nums1[i]
        for i in range(size - 1, 0, -1):
            ones[i] = ones[2 * i] + ones[2 * i + 1]

        def apply_flip(node):
            ones[node] = length[node] - ones[node]
            lazy[node] = not lazy[node]

        def push_down(node):
            if lazy[node]:
                apply_flip(2 * node)
                apply_flip(2 * node + 1)
                lazy[node] = False

        def update(node, node_l, node_r, l, r):
            if r < node_l or node_r < l:
                return
            if l <= node_l and node_r <= r:
                apply_flip(node)
                return
            push_down(node)
            mid = (node_l + node_r) // 2
            update(2 * node, node_l, mid, l, r)
            update(2 * node + 1, mid + 1, node_r, l, r)
            ones[node] = ones[2 * node] + ones[2 * node + 1]

        total2 = sum(nums2)
        res = []
        for q in queries:
            t = q[0]
            if t == 1:
                l, r = q[1], q[2]
                if size > 0 and l <= r:
                    update(1, 0, size - 1, l, min(r, n - 1))
            elif t == 2:
                p = q[1]
                total2 += p * ones[1]
            else:
                res.append(total2)
        return res

