var handleQuery = function(nums1, nums2, queries) {
    const n = nums1.length;
    let size = 1;
    while (size < n) size *= 2;
    const ones = new Array(2 * size).fill(0);
    const length_ = new Array(2 * size).fill(0);
    const lazy = new Array(2 * size).fill(false);
    for (let i = 0; i < size; i++) length_[size + i] = 1;
    for (let i = size - 1; i >= 1; i--) length_[i] = length_[2 * i] + length_[2 * i + 1];
    for (let i = 0; i < n; i++) ones[size + i] = nums1[i];
    for (let i = size - 1; i >= 1; i--) ones[i] = ones[2 * i] + ones[2 * i + 1];

    function applyFlip(node) {
        ones[node] = length_[node] - ones[node];
        lazy[node] = !lazy[node];
    }
    function pushDown(node) {
        if (lazy[node]) {
            applyFlip(2 * node);
            applyFlip(2 * node + 1);
            lazy[node] = false;
        }
    }
    function update(node, nodeL, nodeR, l, r) {
        if (r < nodeL || nodeR < l) return;
        if (l <= nodeL && nodeR <= r) { applyFlip(node); return; }
        pushDown(node);
        const mid = (nodeL + nodeR) >> 1;
        update(2 * node, nodeL, mid, l, r);
        update(2 * node + 1, mid + 1, nodeR, l, r);
        ones[node] = ones[2 * node] + ones[2 * node + 1];
    }

    let total2 = 0;
    for (const v of nums2) total2 += v;
    const res = [];
    for (const q of queries) {
        const t = q[0];
        if (t === 1) {
            const l = q[1], r = q[2];
            if (size > 0 && l <= r) update(1, 0, size - 1, l, Math.min(r, n - 1));
        } else if (t === 2) {
            const p = q[1];
            total2 += p * ones[1];
        } else {
            res.push(total2);
        }
    }
    return res;
};
